#include <string.h>

int main() {
    int t;
    scanf("%d", &t);

    char s[1005], p[1005], result[2100];
    int pos;

    while (t--) {
        scanf("%s %s", s, p);
        scanf("%d", &pos);

        int lenS = strlen(s);

        strncpy(result, s, pos - 1);
        result[pos - 1] = '\0';

        strcat(result, p);
        strcat(result, s + (pos - 1));

        printf("%s\n", result);
    }

